const input = $input.first().json;
function buildQs(obj) { return Object.entries(obj).filter(([k,v]) => v !== undefined && v !== null).map(([k,v]) => encodeURIComponent(k) + '=' + encodeURIComponent(String(v))).join('&'); }

const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.jira&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;
if (!creds.atlassian_email || !creds.atlassian_api_token || !creds.atlassian_site) {
  return [{ json: { error: 'Jira credentials not configured. Need atlassian_email, atlassian_api_token, atlassian_site.' } }];
}

const site = creds.atlassian_site.replace(/^https?:\/\//, '').replace(/\/$/, '');
const API = 'https://' + site + '/rest/api/3';
const basic = Buffer.from(creds.atlassian_email + ':' + creds.atlassian_api_token).toString('base64');
const authHeaders = { 'Authorization': 'Basic ' + basic, 'Accept': 'application/json' };
const jsonHeaders = { ...authHeaders, 'Content-Type': 'application/json' };

function textToAdf(text) {
  if (!text) return null;
  return { type: 'doc', version: 1, content: [{ type: 'paragraph', content: [{ type: 'text', text: String(text) }] }] };
}

function adfToText(adf) {
  if (!adf) return '';
  if (typeof adf === 'string') return adf;
  let out = '';
  function walk(n) {
    if (!n) return;
    if (n.type === 'text' && n.text) out += n.text;
    if (n.type === 'hardBreak') out += '\n';
    if (Array.isArray(n.content)) n.content.forEach(walk);
    if (n.type === 'paragraph' || n.type === 'heading') out += '\n';
  }
  walk(adf);
  return out.trim();
}

function truncate(text, max) {
  max = max || 5000;
  if (text.length > max) return text.substring(0, max) + '\n\n... (truncated, ' + text.length + ' chars total)';
  return text;
}

function issueUrl(key) {
  return 'https://' + site + '/browse/' + key;
}

function fmtIssueLine(iss) {
  const f = iss.fields || {};
  const status = f.status ? f.status.name : '?';
  const type = f.issuetype ? f.issuetype.name : '?';
  const assignee = f.assignee ? f.assignee.displayName : 'unassigned';
  return iss.key + ' [' + status + '] [' + type + '] ' + (f.summary || '') + ' (@' + assignee + ')';
}

// === list_projects ===
if (action === 'list_projects') {
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/project/search?maxResults=50&expand=lead', headers: authHeaders });
    const items = r.values || [];
    if (items.length === 0) return [{ json: { result: 'No projects.' } }];
    let out = 'Projects (' + items.length + (r.total ? ' of ' + r.total : '') + '):\n';
    for (const p of items) {
      out += '  ' + p.key + ' — ' + p.name + ' (' + (p.projectTypeKey || '?') + ')';
      if (p.lead && p.lead.displayName) out += ' lead: ' + p.lead.displayName;
      out += '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Jira list_projects failed: ' + err.message } }];
  }

// === search_issues ===
} else if (action === 'search_issues') {
  const jql = input.jql;
  if (!jql) return [{ json: { error: 'Parameter "jql" is required. Examples: "assignee = currentUser() AND status != Done", "project = KAN ORDER BY created DESC".' } }];
  const limit = Math.min(parseInt(input.limit) || 20, 100);
  const fields = input.fields || 'summary,status,assignee,priority,issuetype,created,updated';
  try {
    const qs = buildQs({ jql, maxResults: String(limit), fields });
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/search/jql?' + qs, headers: authHeaders });
    const items = r.issues || [];
    if (items.length === 0) return [{ json: { result: 'No issues matched JQL: ' + jql } }];
    let out = 'Issues (' + items.length + '):\n';
    for (const it of items) out += fmtIssueLine(it) + '\n';
    if (r.nextPageToken) out += '\n(more results available — refine JQL or increase limit)\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Jira search_issues failed: ' + msg } }];
  }

// === get_issue ===
} else if (action === 'get_issue') {
  const key = input.key;
  if (!key) return [{ json: { error: 'Parameter "key" is required (e.g. KAN-1).' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/issue/' + encodeURIComponent(key) + '?fields=summary,description,status,assignee,reporter,priority,issuetype,labels,created,updated,comment,issuelinks,parent', headers: authHeaders });
    const f = r.fields || {};
    let out = '**' + r.key + '** — ' + (f.summary || '') + '\n';
    out += 'Status: ' + (f.status ? f.status.name : '?') + '\n';
    out += 'Type: ' + (f.issuetype ? f.issuetype.name : '?') + '\n';
    if (f.assignee) out += 'Assignee: ' + f.assignee.displayName + ' (accountId: ' + f.assignee.accountId + ')\n';
    else out += 'Assignee: unassigned\n';
    if (f.reporter) out += 'Reporter: ' + f.reporter.displayName + '\n';
    if (f.priority) out += 'Priority: ' + f.priority.name + '\n';
    if (f.labels && f.labels.length) out += 'Labels: ' + f.labels.join(', ') + '\n';
    if (f.parent) out += 'Parent: ' + f.parent.key + ' — ' + (f.parent.fields ? f.parent.fields.summary : '') + '\n';
    if (f.created) out += 'Created: ' + f.created.substring(0, 10) + '\n';
    if (f.updated) out += 'Updated: ' + f.updated.substring(0, 10) + '\n';
    const desc = adfToText(f.description);
    if (desc) out += '\nDescription:\n' + desc + '\n';
    if (f.issuelinks && f.issuelinks.length) {
      out += '\nLinks:\n';
      for (const l of f.issuelinks) {
        const other = l.outwardIssue || l.inwardIssue;
        const dir = l.outwardIssue ? l.type.outward : l.type.inward;
        if (other) out += '  ' + dir + ' ' + other.key + ' — ' + (other.fields ? other.fields.summary : '') + '\n';
      }
    }
    if (f.comment && f.comment.comments && f.comment.comments.length) {
      out += '\nComments (' + f.comment.comments.length + '):\n';
      for (const c of f.comment.comments.slice(0, 5)) {
        const who = c.author ? c.author.displayName : 'unknown';
        out += '  ' + who + ' (' + (c.created || '').substring(0, 10) + '): ' + adfToText(c.body).substring(0, 200) + '\n';
      }
      if (f.comment.comments.length > 5) out += '  ... (' + (f.comment.comments.length - 5) + ' more — use list_comments)\n';
    }
    out += '\n' + issueUrl(r.key);
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Jira get_issue failed: ' + err.message } }];
  }

// === create_issue ===
} else if (action === 'create_issue') {
  const project = input.project;
  const summary = input.summary;
  if (!project) return [{ json: { error: 'Parameter "project" is required (project key, e.g. KAN).' } }];
  if (!summary) return [{ json: { error: 'Parameter "summary" is required.' } }];
  const issuetype = input.issuetype || 'Task';
  const fields = { project: { key: project.toUpperCase() }, summary, issuetype: { name: issuetype } };
  if (input.description) fields.description = textToAdf(input.description);
  if (input.assignee) fields.assignee = { accountId: input.assignee };
  if (input.priority) fields.priority = { name: input.priority };
  if (input.labels) fields.labels = String(input.labels).split(',').map(l => l.trim()).filter(Boolean);
  if (input.parent) fields.parent = { key: input.parent };
  try {
    const r = await helpers.httpRequest({ method: 'POST', url: API + '/issue', headers: jsonHeaders, body: JSON.stringify({ fields }) });
    return [{ json: { result: 'Issue created: ' + r.key + '\n' + issueUrl(r.key) } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Jira create_issue failed: ' + msg } }];
  }

// === update_issue ===
} else if (action === 'update_issue') {
  const key = input.key;
  if (!key) return [{ json: { error: 'Parameter "key" is required (e.g. KAN-1).' } }];
  const fields = {};
  if (input.summary) fields.summary = input.summary;
  if (input.description) fields.description = textToAdf(input.description);
  if (input.assignee !== undefined) fields.assignee = input.assignee ? { accountId: input.assignee } : null;
  if (input.priority) fields.priority = { name: input.priority };
  if (input.labels) fields.labels = String(input.labels).split(',').map(l => l.trim()).filter(Boolean);
  if (Object.keys(fields).length === 0) return [{ json: { error: 'Provide at least one field: summary, description, assignee (accountId), priority, labels.' } }];
  try {
    await helpers.httpRequest({ method: 'PUT', url: API + '/issue/' + encodeURIComponent(key), headers: jsonHeaders, body: JSON.stringify({ fields }) });
    return [{ json: { result: 'Issue ' + key + ' updated.\n' + issueUrl(key) } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Jira update_issue failed: ' + msg } }];
  }

// === add_comment ===
} else if (action === 'add_comment') {
  const key = input.key;
  const text = input.text;
  if (!key) return [{ json: { error: 'Parameter "key" is required.' } }];
  if (!text) return [{ json: { error: 'Parameter "text" is required.' } }];
  try {
    const r = await helpers.httpRequest({ method: 'POST', url: API + '/issue/' + encodeURIComponent(key) + '/comment', headers: jsonHeaders, body: JSON.stringify({ body: textToAdf(text) }) });
    return [{ json: { result: 'Comment added to ' + key + ' (id: ' + r.id + ')' } }];
  } catch (err) {
    return [{ json: { error: 'Jira add_comment failed: ' + err.message } }];
  }

// === list_comments ===
} else if (action === 'list_comments') {
  const key = input.key;
  if (!key) return [{ json: { error: 'Parameter "key" is required.' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/issue/' + encodeURIComponent(key) + '/comment?maxResults=50', headers: authHeaders });
    const items = r.comments || [];
    if (items.length === 0) return [{ json: { result: 'No comments on ' + key + '.' } }];
    let out = 'Comments on ' + key + ' (' + items.length + '):\n\n';
    for (const c of items) {
      const who = c.author ? c.author.displayName : 'unknown';
      const when = (c.created || '').substring(0, 10);
      out += who + ' (' + when + '):\n  ' + adfToText(c.body) + '\n\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Jira list_comments failed: ' + err.message } }];
  }

// === transition_issue ===
} else if (action === 'transition_issue') {
  const key = input.key;
  const target = input.transition;
  if (!key) return [{ json: { error: 'Parameter "key" is required.' } }];
  if (!target) return [{ json: { error: 'Parameter "transition" is required (status name or transition id). Use list_transitions to see options.' } }];
  try {
    const tList = await helpers.httpRequest({ method: 'GET', url: API + '/issue/' + encodeURIComponent(key) + '/transitions', headers: authHeaders });
    const transitions = tList.transitions || [];
    let match = transitions.find(t => t.id === String(target));
    if (!match) {
      const t = String(target).toLowerCase();
      match = transitions.find(x => x.name.toLowerCase() === t) || transitions.find(x => x.to && x.to.name.toLowerCase() === t) || transitions.find(x => x.name.toLowerCase().includes(t));
    }
    if (!match) {
      const names = transitions.map(x => x.name).join(', ');
      return [{ json: { error: 'No transition matching "' + target + '". Available: ' + names } }];
    }
    await helpers.httpRequest({ method: 'POST', url: API + '/issue/' + encodeURIComponent(key) + '/transitions', headers: jsonHeaders, body: JSON.stringify({ transition: { id: match.id } }) });
    return [{ json: { result: key + ' transitioned via "' + match.name + '" -> ' + match.to.name + '.' } }];
  } catch (err) {
    return [{ json: { error: 'Jira transition_issue failed: ' + err.message } }];
  }

// === list_transitions ===
} else if (action === 'list_transitions') {
  const key = input.key;
  if (!key) return [{ json: { error: 'Parameter "key" is required.' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/issue/' + encodeURIComponent(key) + '/transitions', headers: authHeaders });
    const items = r.transitions || [];
    if (items.length === 0) return [{ json: { result: 'No transitions available from current state.' } }];
    let out = 'Available transitions for ' + key + ':\n';
    for (const t of items) out += '  [' + t.id + '] "' + t.name + '" — moves to: ' + t.to.name + '\n';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Jira list_transitions failed: ' + err.message } }];
  }

// === list_issue_types ===
} else if (action === 'list_issue_types') {
  const project = input.project;
  if (!project) return [{ json: { error: 'Parameter "project" is required (project key, e.g. KAN).' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/issue/createmeta/' + encodeURIComponent(project.toUpperCase()) + '/issuetypes', headers: authHeaders });
    const items = r.issueTypes || r.values || [];
    if (items.length === 0) return [{ json: { result: 'No issue types for project ' + project + '.' } }];
    let out = 'Issue types for ' + project.toUpperCase() + ':\n';
    for (const t of items) out += '  ' + t.name + (t.subtask ? ' (subtask)' : '') + (t.description ? ' — ' + t.description : '') + '\n';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Jira list_issue_types failed: ' + err.message } }];
  }

// === link_issues ===
} else if (action === 'link_issues') {
  const from = input.from;
  const to = input.to;
  const type = input.type || 'Relates';
  if (!from || !to) return [{ json: { error: 'Parameters "from" and "to" are required (issue keys, e.g. KAN-1 and KAN-2).' } }];
  try {
    const body = { type: { name: type }, inwardIssue: { key: to }, outwardIssue: { key: from } };
    await helpers.httpRequest({ method: 'POST', url: API + '/issueLink', headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: from + ' linked to ' + to + ' (type: ' + type + ').' } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Jira link_issues failed: ' + msg + '. Valid types: Blocks, Duplicate, Relates, Cloners.' } }];
  }

// === list_users ===
} else if (action === 'list_users') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required (name or email fragment).' } }];
  const limit = Math.min(parseInt(input.limit) || 10, 50);
  try {
    const qs = buildQs({ query, maxResults: String(limit) });
    const r = await helpers.httpRequest({ method: 'GET', url: API + '/user/search?' + qs, headers: authHeaders });
    const items = Array.isArray(r) ? r : [];
    if (items.length === 0) return [{ json: { result: 'No users matched "' + query + '".' } }];
    let out = 'Users (' + items.length + '):\n';
    for (const u of items) {
      out += '  ' + u.displayName + ' (accountId: ' + u.accountId + (u.emailAddress ? ', ' + u.emailAddress : '') + ')\n';
    }
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Jira list_users failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: list_projects, search_issues, get_issue, create_issue, update_issue, add_comment, transition_issue, list_users, list_comments, list_transitions, list_issue_types, link_issues.' } }];
}
